#include <bits/stdc++.h>
#define int long long
using namespace std;
const int p = 1000000007;
int qp (int x, int y) {
    int res = 1;
    for (int now = x; y; now = now * now % p, y >>= 1) {
        (y & 1) && (res = res * now % p);
    }
    return res;
}
signed main() {
    ios::sync_with_stdio (0);
    cin.tie (0), cout.tie (0);
    int T;
    cin >> T;
    while (T--) {
        int n, m;
        cin >> n >> m;
        if (n == 1) {
            cout << ((m << 1) + 1) % p << '\n';
        } else if (n == 2) {
            cout << ((qp (n, m + 1) + qp (n, m + 2) + p - 1 - n) % p * qp (n - 1, p - 2) % p + p - n * (m + 1) % p) % p << '\n';
        } else {
            cout << ((qp (n, m + 1) + qp (n, m + 2) + p - 1 - n) % p * qp (n - 1, p - 2) % p + p - n * (qp (n - 1, m + 1) + p - 1) % p * qp (n - 2, p - 2) % p) % p << '\n';
        }
    }
    return 0;
}
